function LChildWnd:ResetChildCanvasAttr()

    local sortingOrder = self:GetWndSortOrder()
    local sortLayer = self:GetWndSortLayer()

    local canvasRecord = self._childCanvasRecord or {}

    local wndTrans = self._wndTrans
    if not CS.IsValidObject(wndTrans) then
        return
    end
    local childCanvasList = wndTrans:GetComponentsInChildren(typeofCanvas, true)
    for k=1, childCanvasList.Length do
        local canvasChild = childCanvasList[k-1]
        local instanceId = canvasChild:GetInstanceID()
        local default = canvasRecord[instanceId]
        if not default then
            default = canvasChild.sortingOrder
            canvasRecord[instanceId] = default
        end

        canvasChild.sortingOrder = default +  sortingOrder
        canvasChild.sortingLayerName = sortLayer

    end

    self._childCanvasRecord = canvasRecord
end

return LChildWnd